using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: EF Core 9 renamed the default discriminator JSON
        // property from "Discriminator" to "$type". Existing documents use
        // "Discriminator", so preserve the old name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: EF Core 9 no longer synthesizes the Cosmos `id`
        // as "Discriminator|Key" — it now uses just the key value.  Existing
        // documents have ids like "Blog|1", so we keep the EF8-era __id shadow
        // property mapped to the JSON "id" and mark it with the old value format.
        modelBuilder.Entity<Blog>()
            .Property<string>("__id")
            .ToJsonProperty("id")
            .HasValueGenerator<IdValueGenerator>();

        // Breaking change 3: HasIndex() on Cosmos now throws instead of being
        // silently ignored.  The previous HasIndex(b => b.Name) has been removed.
    }
}

/// <summary>
/// Reproduces the EF Core 8 id value format ("Discriminator|Key") so that
/// existing Cosmos documents remain readable.
/// </summary>
class IdValueGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(
        Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
            ?? entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue?.ToString() ?? "";
        return $"{discriminator}|{key}";
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

